import React from 'react';
import { LabelMoney, Select } from '@linm-soft-org/linm-web-common-components';
import type { CashVoucherFormViewModel } from '../hooks/useCashVoucherFormController';
import styles from '../../../../../styles/documentForm.module.css';

type Props = Pick<
  CashVoucherFormViewModel,
  | 'labels'
  | 'tid'
  | 'viewSectionClass'
  | 'processingLevel'
  | 'setProcessingLevel'
  | 'processingOpts'
  | 'selectDisabled'
  | 'totalAmount'
  | 'defaultProcessingLevel'
>;

export const CashVoucherFooterSection: React.FC<Props> = ({
  labels,
  tid,
  viewSectionClass,
  processingLevel,
  setProcessingLevel,
  processingOpts,
  selectDisabled,
  totalAmount,
  defaultProcessingLevel,
}) => {
  // For new forms, fall back to defaultProcessingLevel if not yet set in form state
  const effectiveLevel = processingLevel || defaultProcessingLevel || '';
  return (
    <div className={[styles.footer, viewSectionClass].filter(Boolean).join(' ')}>
      <div className={styles.footerLeft}>
        <label className={styles.label}>{labels.processingLevel}</label>
        <Select
          data-testid={tid('field-processingLevel')}
          options={processingOpts}
          value={effectiveLevel}
          onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setProcessingLevel(e.target.value)}
          disabled={selectDisabled}
          title={selectDisabled ? 'Chỉ xem — nhấn Sửa để đổi mức xử lý' : undefined}
        />
      </div>
      <div className={styles.totalBlock}>
        <LabelMoney
          label={`${labels.totalLabel}:`}
          value={totalAmount}
          variant="footer"
          emphasize
          data-testid={tid('footer-totalAmount')}
        />
      </div>
    </div>
  );
};
