import React, { useEffect, useRef } from 'react';
import { dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { VoucherFormToolbar } from '../../../../../components/voucher';
import { VoucherFormStatusGroup } from '../../../../../components/voucher/VoucherFormStatusGroup';
import { useTopbarAutoHideOnScroll, useVoucherFormShellHeight, useFormEmbedSlideout } from '../../../../../components/form';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import { resolveVoucherViewModeHint } from '../../../../../utils/voucherProcessingLevelDisplay';
import type { CashVoucherKind } from '../../../../../components/kt/CashVoucherList';
import { useCashVoucherFormController } from '../hooks/useCashVoucherFormController';
import { CashVoucherValidationBanner } from './CashVoucherValidationBanner';
import { CashVoucherHeaderSection } from './CashVoucherHeaderSection';
import { CashVoucherLinesSection } from './CashVoucherLinesSection';
import { CashVoucherFooterSection } from './CashVoucherFooterSection';
import { CashVoucherFormModals } from './CashVoucherFormModals';
import styles from '../../../../../styles/documentForm.module.css';

export const CashVoucherFormParent: React.FC<{ kind: CashVoucherKind }> = ({ kind }) => {
  const vm = useCashVoucherFormController(kind);
  const embedSlideout = useFormEmbedSlideout();
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const dispatch = vm.dispatch;
  useVoucherFormShellHeight(shellRef, !embedSlideout);
  useTopbarAutoHideOnScroll(scrollRef, !embedSlideout);

  // Must be before early returns (Rules of Hooks)
  const tabLabel = vm.isNew ? vm.labels?.createTitle : vm.labels?.title;
  useEffect(() => {
    if (vm.voucherNumber && typeof window.__LINM_UPDATE_TAB_TITLE__ === 'function') {
      window.__LINM_UPDATE_TAB_TITLE__(`${tabLabel} — ${vm.voucherNumber}`);
    }
  }, [vm.voucherNumber, tabLabel]);
  useEffect(() => {
    window.__LINM_IS_CURRENT_TAB_DIRTY__ = vm.isDirty;
    return () => { window.__LINM_IS_CURRENT_TAB_DIRTY__ = false; };
  }, [vm.isDirty]);

  if (vm.initError) {
    return (
      <div className={styles.pageVoucher} data-testid={vm.tid('init-error')}>
        <div className={styles.formErrorMessage}>
          <p className={styles.formErrorTitle}>Không thể tải dữ liệu form</p>
          <p className={styles.formErrorDetail}>{vm.initError}</p>
        </div>
      </div>
    );
  }

  if (vm.initLoading || vm.showInitialLoading) {
    return (
      <div className={styles.formInitLoading} data-testid={vm.tid('form-init-loading')}>
        <div className={styles.formInitSpinner} />
        <p>Đang tải...</p>
      </div>
    );
  }

  const {
    cfg,
    labels,
    isNew,
    voucherNumber,
    toolbarMode,
    isViewMode,
    status,
    saving,
    tid,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    handleBack,
    setShowApproveModal,
    handleCopy,
    setShowPrintModal,
    setShowHistoryModal,
    setShowSearchSlideout,
    handleNew,
    handleEdit,
    handleSave,
    handleCancel,
    setShowDeleteModal,
    saveLabel,
    refreshing,
    validationErrors,
    bannerClosed,
    bannerExpanded,
    setBannerExpanded,
    setBannerClosed,
    validationBannerId,
    processingLevel,
    setProcessingLevel,
    processingOpts,
    selectDisabled,
    totalAmount,
    viewSectionClass,
    toolbarDisabledReasons,
    canViewLedger,
    canViewLinkedInvoices,
    showEditDelete,
    canApproveToolbar,
    showApproveToolbar,
    canCopyToolbar,
    canPrintToolbar,
    canDeleteToolbar,
    canSaveToolbar,
    copySourceVoucherCode,
  } = vm;

  const documentHistoryType = 'documentHistoryType' in cfg ? cfg.documentHistoryType : undefined;

  const processingLevelLabel = formatProcessingLevelFromOptions(processingLevel, processingOpts);

  // ── Cross-company: force View-only, show banner, hide edit buttons ──
  const isCrossCompany = vm.crossCompany !== null;
  const effectiveShowEditDelete = isCrossCompany ? false : showEditDelete;
  const effectiveCanSaveToolbar = isCrossCompany ? false : canSaveToolbar;
  const effectiveCanDeleteToolbar = isCrossCompany ? false : canDeleteToolbar;
  const effectiveCanCopyToolbar = isCrossCompany ? false : canCopyToolbar;
  const effectiveCanApproveToolbar = isCrossCompany ? false : canApproveToolbar;

  return (
    <div
      ref={shellRef}
      className={[
        styles.pageVoucher,
        embedSlideout ? styles.pageVoucherSlideoutEmbed : '',
        refreshing ? styles.pageRefreshing : '',
      ].filter(Boolean).join(' ')}
      data-voucher-form-shell
      data-form-embed-slideout={embedSlideout || undefined}
      data-testid={tid('form')}
      aria-busy={refreshing}
    >
      {!embedSlideout && (
      <div className={styles.pageFormHeader}>
        <div className={styles.stickyTop}>
          <VoucherFormToolbar
          testIdPrefix={cfg.testIdPrefix}
          title={isNew ? labels.createTitle : `${labels.title} — ${voucherNumber || '...'}`}
          processingLevelBadge={
            !isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
          }
          formMode={toolbarMode}
          viewModeHint={resolveVoucherViewModeHint({
            formMode: toolbarMode,
            isNew,
            status,
            processingLevel,
            canEditWhenView: showEditDelete,
          })}
          copySourceVoucherCode={copySourceVoucherCode}
          showApproveButton={showApproveToolbar}
          canApprove={effectiveCanApproveToolbar}
          showPostButton={false}
          canPost={false}
          canCopy={effectiveCanCopyToolbar}
          canPrint={canPrintToolbar}
          canHistory={!isNew && !!documentHistoryType}
          showEditButton={effectiveShowEditDelete}
          showDeleteButton={effectiveCanDeleteToolbar}
          showNewButton={isCrossCompany ? false : (vm.formPermissions?.canCreate ?? false)}
          canEdit={effectiveShowEditDelete}
          canDelete={effectiveCanDeleteToolbar}
          canSave={effectiveCanSaveToolbar}
          disabledReasons={toolbarDisabledReasons}
          saving={saving}
          searchNav={hasSearchNav ? {
            index: searchNavIndex,
            total: searchResultIds.length,
            onFirst: () => navigateToSearchId(searchResultIds[0]),
            onPrev: () => navigateToSearchId(searchResultIds[searchNavIndex - 1]),
            onNext: () => navigateToSearchId(searchResultIds[searchNavIndex + 1]),
            onEnd: () => navigateToSearchId(searchResultIds[searchResultIds.length - 1]),
          } : undefined}
          onBack={handleBack}
          onApprove={() => setShowApproveModal(true)}
          onPost={() => {}}
          canViewLedger={canViewLedger}
          onViewLedger={() => vm.setShowLedgerModal(true)}
          canViewLinkedVoucher={canViewLinkedInvoices}
          onViewLinkedVoucher={() => vm.setShowLinkedInvoicesSlideout(true)}
          viewLinkedVoucherLabel="Xem hóa đơn"
          onCopy={handleCopy}
          onPrint={() => setShowPrintModal(true)}
          onHistory={documentHistoryType ? () => setShowHistoryModal(true) : undefined}
          onSearch={() => setShowSearchSlideout(true)}
          onNew={handleNew}
          onEdit={handleEdit}
          onSave={handleSave}
          onCancel={handleCancel}
          onDelete={() => setShowDeleteModal(true)}
          saveLabel={saveLabel}
          insetShell
        />
        </div>
      </div>
      )}

      <div ref={scrollRef} className={styles.pageFormScroll} data-testid={tid('form-scroll')}>
        <CashVoucherValidationBanner
          validationErrors={validationErrors}
          bannerClosed={bannerClosed}
          bannerExpanded={bannerExpanded}
          setBannerExpanded={setBannerExpanded}
          setBannerClosed={setBannerClosed}
          validationBannerId={validationBannerId}
          tid={tid}
        />

        {vm.crossCompany && (
          <div
            style={{
              background: '#fef3c7',
              border: '1px solid #f59e0b',
              borderRadius: 6,
              padding: '8px 14px',
              margin: '0 0 8px',
              fontSize: 13,
              display: 'flex',
              alignItems: 'center',
              gap: 8,
              color: '#92400e',
            }}
          >
            <span style={{ fontWeight: 600 }}>Xem chứng từ khác đơn vị</span>
            <span>
              Đơn vị chứng từ: <strong>{vm.crossCompany.targetCompanyCode}</strong>
              {' · '}Đơn vị đăng nhập: <strong>{vm.crossCompany.activeCompanyCode}</strong>
            </span>
            <span style={{ fontSize: 12, color: '#b45309', marginLeft: 'auto' }}>
              Chỉ xem được — không thể sửa/xóa
            </span>
          </div>
        )}

        <CashVoucherHeaderSection vm={vm} />
        <CashVoucherLinesSection vm={vm} />
      </div>

      <div className={styles.pageFormFooter} data-testid={tid('form-footer')}>
        <CashVoucherFooterSection
          labels={labels}
          tid={tid}
          viewSectionClass={viewSectionClass}
          processingLevel={processingLevel}
          setProcessingLevel={setProcessingLevel}
          processingOpts={processingOpts}
          selectDisabled={selectDisabled}
          totalAmount={totalAmount}
          defaultProcessingLevel={vm.defaultProcessingLevel}
        />
      </div>

      <CashVoucherFormModals vm={vm} />
    </div>
  );
};

export default CashVoucherFormParent;
