import { useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import { getActiveCompanyCode } from '@linm-soft-org/linm-web-common-components';
import { FormMode } from '../components/form';

/** Query param for cross-company view = `?companyCode=FM02`. */
export const CROSS_COMPANY_URL_PARAM = 'companyCode';

/**
 * Detect if current form was opened from cross-company context (admin sync/import/report).
 * When `companyCode` param differs from active company:
 *  - Force FormMode.View (view-only)
 *  - Show cross-company banner UI
 *  - API calls must pass the override companyCode (middleware handles via ?companyCode query)
 */
export interface CrossCompanyViewResult {
  /** Target company code from URL param (null if same-company). */
  targetCompanyCode: string | null;
  /** Active company where the user is logged in. */
  activeCompanyCode: string | null;
  /** True when user is viewing data from a different company. */
  isCrossCompanyView: boolean;
  /** The FormMode to enforce (always View when cross-company). */
  enforcedFormMode: FormMode | null;
}

export function useCrossCompanyView(): CrossCompanyViewResult {
  const location = useLocation();

  return useMemo(() => {
    const searchParams = new URLSearchParams(location.search);
    const paramCode = searchParams.get(CROSS_COMPANY_URL_PARAM)?.trim().toUpperCase() || null;
    const activeCompany = getActiveCompanyCode();

    if (!paramCode || paramCode === activeCompany) {
      return {
        targetCompanyCode: null,
        activeCompanyCode: activeCompany,
        isCrossCompanyView: false,
        enforcedFormMode: null,
      };
    }

    return {
      targetCompanyCode: paramCode,
      activeCompanyCode: activeCompany,
      isCrossCompanyView: true,
      enforcedFormMode: FormMode.View,
    };
  }, [location.search]);
}
