import React from 'react';
import { Button, Slideout } from '@linm-soft-org/linm-web-common-components';
import { formatMoneyVnd } from '../../utils/formatters';
import { openWorkspaceTab } from '../../utils/openWorkspaceTab';
import { DOCUMENT_TYPE, DOCUMENT_TYPE_LABEL } from '../../workspace/workspaceTabTypes';
import type { LinkedSalesInvoiceLineDto } from '../../services/kt/models';
import styles from '../../styles/documentForm.module.css';

export type LinkedInvoicesViewSlideoutProps = {
  isOpen: boolean;
  onClose: () => void;
  invoices: LinkedSalesInvoiceLineDto[];
  returnPath: string;
  returnTitle?: string;
  navigate: (path: string) => void;
  testIdPrefix: string;
};

function toDateOnly(value: string): string {
  if (!value) return '';
  return value.slice(0, 10);
}

export const LinkedInvoicesViewSlideout: React.FC<LinkedInvoicesViewSlideoutProps> = ({
  isOpen,
  onClose,
  invoices,
  returnPath,
  returnTitle,
  navigate,
  testIdPrefix,
}) => {
  const footer = (
    <div className={styles.modalActions}>
      <Button variant="secondary" onClick={onClose} data-testid={`${testIdPrefix}-linked-invoice-close`}>
        Đóng
      </Button>
    </div>
  );

  const invoiceLabel = DOCUMENT_TYPE_LABEL[DOCUMENT_TYPE.SALES_INVOICE] ?? 'Hóa đơn bán';

  const openInvoice = (inv: LinkedSalesInvoiceLineDto) => {
    openWorkspaceTab(
      {
        path: inv.viewUrl,
        title: `${invoiceLabel} — ${inv.invoiceCode}`,
        returnPath,
        returnTitle,
        documentType: DOCUMENT_TYPE.SALES_INVOICE,
      },
      navigate,
    );
    onClose();
  };

  return (
    <Slideout
      isOpen={isOpen}
      onClose={onClose}
      title="Hóa đơn liên kết"
      width="min(820px, 92vw)"
      customFooter={footer}
      data-testid={`${testIdPrefix}-linked-invoice-slideout`}
    >
      {invoices.length === 0 ? (
        <p data-testid={`${testIdPrefix}-linked-invoice-empty`}>Chưa có hóa đơn liên kết trên phiếu thu.</p>
      ) : (
        <div className={styles.tableWrapper}>
          <table className={styles.linesTable}>
            <thead>
              <tr>
                <th>Số HĐ</th>
                <th>Ngày HĐ</th>
                <th>Tiền HĐ</th>
                <th>Phân bổ</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {invoices.map((inv, idx) => (
                <tr key={`${inv.invoiceId}-${idx}`} data-testid={`${testIdPrefix}-linked-invoice-row-${idx}`}>
                  <td>{inv.invoiceCode}</td>
                  <td>{toDateOnly(inv.invoiceDate)}</td>
                  <td style={{ textAlign: 'right' }}>{formatMoneyVnd(inv.invoiceTotalAmount)}</td>
                  <td style={{ textAlign: 'right' }}>{formatMoneyVnd(inv.allocatedAmount)}</td>
                  <td>
                    <Button
                      variant="secondary"
                      type="button"
                      data-testid={`${testIdPrefix}-linked-invoice-open-${idx}`}
                      onClick={() => openInvoice(inv)}
                    >
                      Mở hóa đơn
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </Slideout>
  );
};
